import { Link } from "react-router-dom";

export default function Breadcrumb({ items }) {
  return (
    <nav aria-label="breadcrumb">
      <ol className="breadcrumb">
        {items.map((item, index) => (
          <li
            key={index}
            className={`breadcrumb-item ${index === items.length - 1 ? "active" : ""}`}
            aria-current={index === items.length - 1 ? "page" : undefined}
          >
            {index === items.length - 1 ? (
              item.label
            ) : (
              <Link to={item.path}>{item.label}</Link>
            )}
          </li>
        ))}
      </ol>
    </nav>
  );
}

import { useAuth0 } from "@auth0/auth0-react";
import { useCallback } from "react";
import { getEnv } from "@/utils/getEnv";

export function useAuth() {
  const { getAccessTokenSilently } = useAuth0();

  const getToken = useCallback(async () => {
    try {
      const env = getEnv(); 
      const audience = env.VITE_AUTH0_AUDIENCE;

      const token = await getAccessTokenSilently({
        authorizationParams: { audience },
      });

      // Vérification du format du token
      const parts = token.split(".");
      if (parts.length === 5) {
        console.warn("[Auth] Format JWE (token chiffré) ⚠️");
      } else if (parts.length !== 3) {
        console.warn("[Auth] Format token inattendu ⚠️");
      }

      return token;
    } catch (err) {
      console.error("Impossible de récupérer le token", err);
      throw err;
    }
  }, [getAccessTokenSilently]);

  return { getToken };
}

import { useMemo } from "react";
import { useAuth } from "@/hooks/useAuth";
import { getEnv } from "@/utils/getEnv"; 

const env = getEnv();
const API_ROOT = (env.VITE_API_URL || 'http://localhost:8080').replace(/\/$/, '');
const API_BASE = `${API_ROOT}/api/sellers`;

console.log("API_BASE sellers =", API_BASE);

export function useSellerService() {
  const { getToken } = useAuth();

  return useMemo(() => {
    const request = async (url, options = {}) => {
      const token = await getToken();
      const res = await fetch(url, {
        ...options,
        headers: {
          ...options.headers,
          Authorization: `Bearer ${token}`,
        },
      });
      const text = await res.text();

      if (!res.ok) {
        throw new Error(`Erreur ${res.status}: ${text}`);
      }

      try {
        return JSON.parse(text);
      } catch {
        return true; // pour les DELETE qui ne renvoient rien
      }
    };

    return {
      fetchMySeller: () => request(`${API_BASE}/me`),
      createSeller: (data) =>
        request(API_BASE, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(data),
        }),
      updateSeller: (id, data) =>
        request(`${API_BASE}/${id}`, {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(data),
        }),
      deleteSeller: () => request(API_BASE, { method: "DELETE" }),
      checkIdentifier: (identifier, sellerId) =>
        request(`${API_BASE}/check-identifier?identifier=${identifier}${sellerId ? `&id=${sellerId}` : ''}`),
      testSmtpResend: (smtpData) =>
        request(`${API_BASE}/smtp/test-resend`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(smtpData),
        }),
    };
  }, [getToken]);
}

// frontend/src/modules/sellers/useSellers.js
import { useState, useEffect } from 'react';
import { useSellerService } from '@/services/sellers';

export default function useSellers() {
  const { fetchSellers } = useSellerService();
  const [sellers, setSellers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    let isMounted = true;

    const loadSellers = async () => {
      try {
        const data = await fetchSellers();
        if (isMounted) setSellers(data);
      } catch (err) {
        console.error(err);
        if (isMounted) setError('Erreur lors du chargement des vendeurs');
      } finally {
        if (isMounted) setLoading(false);
      }
    };

    loadSellers();

    return () => {
      isMounted = false;
    };
  }, [fetchSellers]);

  return { sellers, setSellers, loading, error };
}

import React, { useRef, useState, useEffect } from "react";

const EllipsisCell = ({ value, maxWidth = "200px" }) => {
  const spanRef = useRef(null);
  const [isTruncated, setIsTruncated] = useState(false);

  useEffect(() => {
    const el = spanRef.current;
    if (el) {
      setIsTruncated(el.scrollWidth > el.clientWidth);
    }
  }, [value]);

  return (
    <span
      ref={spanRef}
      style={{
        display: "block",
        whiteSpace: "nowrap",
        overflow: "hidden",
        textOverflow: "ellipsis",
        maxWidth,
      }}
      title={isTruncated ? value : undefined} // seulement si tronqué
    >
      {value}
    </span>
  );
};

export default EllipsisCell;

// frontend/src/modules/sellers/sellerColumns.js
import React from 'react';
import { useNavigate } from 'react-router-dom';
import EllipsisCell from '../../components/common/EllipsisCell';

export default function useSellerColumns() {
  const navigate = useNavigate();

  return [
    {
      name: 'Actions',
      cell: row => (
        <button className="btn btn-sm" onClick={() => navigate(`/sellers/${row.id}`)}>
          ✏️
        </button>
      ),
      ignoreRowClick: true,
      width: '50px',
    },
    { 
      name: 'Identifiant', 
      selector: row => row.legal_identifier, 
      sortable: true, 
      width: '150px',
      cell: row => <EllipsisCell value={row.legal_identifier} maxWidth="150px" />
    },
    { 
      name: 'Nom légal', 
      selector: row => row.legal_name, 
      sortable: true,
      cell: row => <EllipsisCell value={row.legal_name} />
    },
    { 
      name: 'Adresse', 
      selector: row => row.address, 
      sortable: true,
      cell: row => <EllipsisCell value={row.address} />
    },
    { 
      name: 'Code postal', 
      selector: row => row.postal_code, 
      sortable: true, 
      width: '120px',
      cell: row => <EllipsisCell value={row.postal_code} maxWidth="120px" />
    },
    { 
      name: 'Ville', 
      selector: row => row.city, 
      sortable: true,
      cell: row => <EllipsisCell value={row.city} />
    },
    { 
      name: 'Pays', 
      selector: row => row.country_code, 
      sortable: true, 
      width: '100px',
      cell: row => <EllipsisCell value={row.country_code} maxWidth="100px" />
    },
    { 
      name: 'Email', 
      selector: row => row.contact_email, 
      sortable: true, 
      width: '200px',
      cell: row => <EllipsisCell value={row.contact_email} maxWidth="200px" />
    },
    { 
      name: 'Téléphone', 
      selector: row => row.phone_number || '', 
      sortable: true, 
      width: '120px',
      cell: row => <EllipsisCell value={row.phone_number || ''} maxWidth="120px" />
    },
  ];
}

