// frontend/src/components/common/AuditPanel.jsx
import React from 'react';
import PropTypes from 'prop-types';

export default function AuditPanel({ createdAt, updatedAt }) {
  // Conversion sécurisée des dates
  const created = createdAt && !isNaN(Date.parse(createdAt)) ? new Date(createdAt) : null;
  const updated = updatedAt && !isNaN(Date.parse(updatedAt)) ? new Date(updatedAt) : null;

  return (
    <div className="p-2 bg-light border rounded">
      <p className="mb-1 text-muted small">
        Créé le {created ? created.toLocaleDateString() : '—'} à {created ? created.toLocaleTimeString() : '—'}
      </p>

      <p className="mb-0 text-muted small">
        Mis à jour le {updated ? updated.toLocaleDateString() : '—'} à {updated ? updated.toLocaleTimeString() : '—'}
      </p>
    </div>
  );
}

AuditPanel.propTypes = {
  createdAt: PropTypes.oneOfType([PropTypes.string, PropTypes.instanceOf(Date)]),
  updatedAt: PropTypes.oneOfType([PropTypes.string, PropTypes.instanceOf(Date)]),
};

import React, { useState } from 'react';
import DataTable from 'react-data-table-component';
import Breadcrumb from '../../components/layout/Breadcrumb';
import useSellers from '../../modules/sellers/useSellers';
import useSellerColumns from '../../modules/sellers/sellerColumns';
import { datatableStyles } from '../../modules/common/datatableStyles'; // <== correction
import AuditPanel from '../../components/common/AuditPanel';

export default function SellersList() {
  const { sellers, loading, error } = useSellers();
  const columns = useSellerColumns();
  const [filterText, setFilterText] = useState('');

  const filteredItems = sellers.filter(item => 
    Object.values(item).some(
      val => val && val.toString().toLowerCase().includes(filterText.toLowerCase())
    )
  );

  const breadcrumbItems = [
    { label: 'Accueil', path: '/' },
    { label: 'Vendeurs', path: '/sellers' },
  ];

  return (
    <div className="container-fluid p-5 mt-4">
      <h1 className="visually-hidden">Liste des vendeurs</h1>

      <Breadcrumb items={breadcrumbItems} />

      {error && <div className="alert alert-danger">{error}</div>}

      <input
        type="text"
        placeholder="Rechercher un vendeur"
        className="form-control mb-3"
        value={filterText}
        onChange={e => setFilterText(e.target.value)}
        style={{ maxWidth: '300px' }}
      />

      <DataTable
        columns={columns}
        data={filteredItems}
        pagination
        paginationPerPage={20}
        highlightOnHover
        striped
        responsive
        dense
        noHeader
        fixedHeader
        fixedHeaderScrollHeight="70vh"
        expandableRows
        expandableRowsComponent={({ data }) => (
          <AuditPanel createdAt={data.created_at} updatedAt={data.updated_at} />
        )}        
        expandOnRowClicked
        progressPending={loading}
        customStyles={datatableStyles} // <== correction
      />
    </div>
  );
}
